import{_ as e,a,b as n}from"./chunks/配置容量限制.DkdWbdOw.js";import{_ as i,o as d,c as l,a2 as o}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Thêm Cloudflare R2 Channel","description":"","frontmatter":{},"headers":[],"relativePath":"vi-VN/upload/cloudflare-r2.md","filePath":"vi-VN/upload/cloudflare-r2.md","lastUpdated":1781962217000}'),r={name:"vi-VN/upload/cloudflare-r2.md"};function c(h,t,u,g,b,m){return d(),l("div",null,[...t[0]||(t[0]=[o('<h1 id="them-cloudflare-r2-channel" tabindex="-1">Thêm Cloudflare R2 Channel <a class="header-anchor" href="#them-cloudflare-r2-channel" aria-label="Permalink to &quot;Thêm Cloudflare R2 Channel&quot;">​</a></h1><h2 id="phu-hop-nhat-khi-nao" tabindex="-1">Phù hợp nhất khi nào <a class="header-anchor" href="#phu-hop-nhat-khi-nao" aria-label="Permalink to &quot;Phù hợp nhất khi nào&quot;">​</a></h2><p>Dùng Cloudflare R2 khi:</p><ul><li>ImgBed site của bạn đã deploy trên Cloudflare và bạn muốn lưu files trong một R2 bucket thuộc cùng Cloudflare account.</li><li>Bạn không muốn cấu hình riêng S3 endpoint, access key và secret key.</li><li>Bạn muốn đọc và ghi qua Worker hoặc Pages R2 binding với ít bước thiết lập nhất.</li></ul><p>Tóm lại:</p><p>R2 channel không được tạo thủ công trong ImgBed admin panel. Trước tiên bạn cần bind một R2 bucket vào Cloudflare project, và binding variable name phải là <code>img_r2</code>.</p><h2 id="can-chuan-bi-gi-truoc-khi-bat-đau" tabindex="-1">Cần chuẩn bị gì trước khi bắt đầu <a class="header-anchor" href="#can-chuan-bi-gi-truoc-khi-bat-đau" aria-label="Permalink to &quot;Cần chuẩn bị gì trước khi bắt đầu&quot;">​</a></h2><ul><li>Một Cloudflare account.</li><li>Một R2 bucket đã có sẵn.</li><li>Quyền quản lý Cloudflare project nơi ImgBed được deploy.</li></ul><h2 id="cau-hinh-trong-cloudflare" tabindex="-1">Cấu hình trong Cloudflare <a class="header-anchor" href="#cau-hinh-trong-cloudflare" aria-label="Permalink to &quot;Cấu hình trong Cloudflare&quot;">​</a></h2><h3 id="_1-tao-r2-bucket" tabindex="-1">1. Tạo R2 Bucket <a class="header-anchor" href="#_1-tao-r2-bucket" aria-label="Permalink to &quot;1. Tạo R2 Bucket&quot;">​</a></h3><ol><li>Đăng nhập Cloudflare Dashboard.</li><li>Mở <code>R2 Object Storage</code>.</li><li>Nhấn Create bucket.</li><li>Chọn bucket name, ví dụ <code>imgbed</code>.</li></ol><p>Bucket này là nơi lưu uploaded files.</p><p><img src="'+e+'" alt="Create an R2 bucket" loading="lazy"></p><h3 id="_2-bind-bucket-vao-imgbed-project" tabindex="-1">2. Bind Bucket vào ImgBed Project <a class="header-anchor" href="#_2-bind-bucket-vao-imgbed-project" aria-label="Permalink to &quot;2. Bind Bucket vào ImgBed Project&quot;">​</a></h3><p>Chọn vị trí binding theo deployment type:</p><table tabindex="0"><thead><tr><th>Deployment Type</th><th>Binding Location</th></tr></thead><tbody><tr><td>Pages</td><td>Current Pages project -&gt; Settings -&gt; Functions -&gt; R2 bucket bindings</td></tr><tr><td>Worker</td><td>Current Worker -&gt; Settings -&gt; Bindings -&gt; R2 bucket bindings</td></tr></tbody></table><p>Khi thêm binding, các field quan trọng là:</p><table tabindex="0"><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td>Variable name</td><td><code>img_r2</code></td></tr><tr><td>R2 bucket</td><td>Chọn bucket bạn đã tạo.</td></tr></tbody></table><p>Variable name phải chính xác là <code>img_r2</code>. Việc upload, đọc và xóa R2 files đều phụ thuộc vào binding name này.</p><h3 id="_3-redeploy-project" tabindex="-1">3. Redeploy Project <a class="header-anchor" href="#_3-redeploy-project" aria-label="Permalink to &quot;3. Redeploy Project&quot;">​</a></h3><p>Sau khi save binding, redeploy ImgBed để Worker hoặc Pages runtime truy cập được <code>img_r2</code>.</p><h2 id="ban-se-thay-gi-trong-imgbed" tabindex="-1">Bạn sẽ thấy gì trong ImgBed <a class="header-anchor" href="#ban-se-thay-gi-trong-imgbed" aria-label="Permalink to &quot;Bạn sẽ thấy gì trong ImgBed&quot;">​</a></h2><p>Khi R2 binding đã sẵn sàng, mở:</p><ol><li>System Settings.</li><li>Upload Settings.</li><li><code>Cloudflare R2</code> channel.</li></ol><p>System tự động tạo một fixed channel:</p><table tabindex="0"><thead><tr><th>Field</th><th>Fixed Value</th></tr></thead><tbody><tr><td>Channel name</td><td><code>Cloudflare R2</code></td></tr><tr><td>Channel type</td><td><code>cfr2</code></td></tr><tr><td>Storage mode</td><td><code>binding</code></td></tr><tr><td>Configuration source</td><td>Environment binding</td></tr></tbody></table><p>Đây là fixed binding channel. Bạn không cần nhấn Add Channel để tạo, và cũng không thể xóa như regular channel.</p><h2 id="cac-field-co-the-sua-trong-admin-panel" tabindex="-1">Các field có thể sửa trong Admin Panel <a class="header-anchor" href="#cac-field-co-the-sua-trong-admin-panel" aria-label="Permalink to &quot;Các field có thể sửa trong Admin Panel&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Tác dụng</th><th>Required</th></tr></thead><tbody><tr><td>Enable channel</td><td>Kiểm soát R2 có tham gia upload selection hay không.</td><td>Yes</td></tr><tr><td>Account ID</td><td>Chỉ dùng khi quota limits được bật và cần query official R2 usage.</td><td>Recommended khi bật quota limits</td></tr><tr><td>Bucket name</td><td>Chỉ dùng khi quota limits được bật và cần query official R2 usage.</td><td>Recommended khi bật quota limits</td></tr><tr><td>Quota limit</td><td>Kiểm soát R2 channel này có tham gia upload selection dựa trên capacity hay không.</td><td>No</td></tr><tr><td>Threshold</td><td>Dừng ghi vào channel này khi usage đạt percentage đã đặt.</td><td>Required khi bật quota limits</td></tr></tbody></table><p>Bạn có thể copy Account ID từ account information panel trong Cloudflare dashboard. Chỉ điền nếu muốn ImgBed query và enforce R2 quota usage.</p><p><img src="'+a+'" alt="Get the Account ID" loading="lazy"></p><h2 id="cac-buoc-thiet-lap" tabindex="-1">Các bước thiết lập <a class="header-anchor" href="#cac-buoc-thiet-lap" aria-label="Permalink to &quot;Các bước thiết lập&quot;">​</a></h2><ol><li>Tạo R2 bucket trong Cloudflare.</li><li>Mở Cloudflare settings của ImgBed project.</li><li>Thêm R2 bucket binding.</li><li>Đặt <code>Variable name</code> là <code>img_r2</code>.</li><li>Chọn R2 bucket đã tạo.</li><li>Save binding và redeploy ImgBed.</li><li>Quay lại ImgBed -&gt; System Settings -&gt; Upload Settings.</li><li>Xác nhận <code>Cloudflare R2</code> channel xuất hiện và đang enabled.</li></ol><p>Nếu muốn R2 tham gia upload selection dựa trên capacity, bật quota limit rồi nhập Account ID, bucket name, quota limit và threshold trước khi save.</p><p><img src="'+n+'" alt="Configure quota limits" loading="lazy"></p><h2 id="cach-kiem-tra" tabindex="-1">Cách kiểm tra <a class="header-anchor" href="#cach-kiem-tra" aria-label="Permalink to &quot;Cách kiểm tra&quot;">​</a></h2><ul><li>Fixed <code>Cloudflare R2</code> channel xuất hiện trong Upload Settings.</li><li>Channel card hiển thị trạng thái enabled.</li><li>Upload thử một file nhỏ thành công và link trả về mở bình thường.</li><li>Nếu mở file thấy <code>R2 database binding is not configured</code>, runtime chưa nhận được <code>img_r2</code> binding. Hãy kiểm tra binding name trong Cloudflare và redeploy project.</li></ul>',37)])])}const f=i(r,[["render",c]]);export{k as __pageData,f as default};
